INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (1, 'FixValue', NULL, NULL, NULL, '2021-06-30 00:00:00', '2021-06-30 00:00:00', false);
INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (2, 'DailyAvg', 'select round(avg(statistics_value),2) as day_avg from t_ds_dq_task_statistics_value where data_time >=date_trunc(''DAY'', ${data_time}) and data_time < date_add(date_trunc(''day'', ${data_time}),1) and unique_code = ${unique_code} and statistics_name = ''${statistics_name}''', 'day_range', 'day_range.day_avg', '2021-06-30 00:00:00', '2021-06-30 00:00:00', true);
INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (3, 'WeeklyAvg', 'select round(avg(statistics_value),2) as week_avg from t_ds_dq_task_statistics_value where  data_time >= date_trunc(''WEEK'', ${data_time}) and data_time <date_trunc(''day'', ${data_time}) and unique_code = ${unique_code} and statistics_name = ''${statistics_name}''', 'week_range', 'week_range.week_avg', '2021-06-30 00:00:00', '2021-06-30 00:00:00', true);
INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (4, 'MonthlyAvg', 'select round(avg(statistics_value),2) as month_avg from t_ds_dq_task_statistics_value where  data_time >= date_trunc(''MONTH'', ${data_time}) and data_time <date_trunc(''day'', ${data_time}) and unique_code = ${unique_code} and statistics_name = ''${statistics_name}''', 'month_range', 'month_range.month_avg', '2021-06-30 00:00:00', '2021-06-30 00:00:00', true);
INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (5, 'Last7DayAvg', 'select round(avg(statistics_value),2) as last_7_avg from t_ds_dq_task_statistics_value where  data_time >= date_add(date_trunc(''day'', ${data_time}),-7) and  data_time <date_trunc(''day'', ${data_time}) and unique_code = ${unique_code} and statistics_name = ''${statistics_name}''', 'last_seven_days', 'last_seven_days.last_7_avg', '2021-06-30 00:00:00', '2021-06-30 00:00:00', true);
INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (6, 'Last30DayAvg', 'select round(avg(statistics_value),2) as last_30_avg from t_ds_dq_task_statistics_value where  data_time >= date_add(date_trunc(''day'', ${data_time}),-30) and  data_time < date_trunc(''day'', ${data_time}) and unique_code = ${unique_code} and statistics_name = ''${statistics_name}''', 'last_thirty_days', 'last_thirty_days.last_30_avg', '2021-06-30 00:00:00', '2021-06-30 00:00:00', true);
INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (7, 'SrcTableTotalRows', 'SELECT COUNT(*) AS total FROM ${src_table} WHERE (${src_filter})', 'total_count', 'total_count.total', '2021-06-30 00:00:00', '2021-06-30 00:00:00', false);
INSERT INTO public.t_ds_dq_comparison_type (id, type, execute_sql, output_table, name, create_time, update_time, is_inner_source) VALUES (8, 'TargetTableTotalRows', 'SELECT COUNT(*) AS total FROM ${target_table} WHERE (${target_filter})', 'total_count', 'total_count.total', '2021-06-30 00:00:00', '2021-06-30 00:00:00', false);


